import{_ as e,o,c as d,ag as t}from"./chunks/framework.HKmjcgbP.js";const h=JSON.parse('{"title":"","description":"","frontmatter":{},"headers":[],"relativePath":"java/大数据/hadoop.md","filePath":"java/大数据/hadoop.md","lastUpdated":1699943249000}'),r={name:"java/大数据/hadoop.md"};function i(p,a,n,l,s,c){return o(),d("div",null,[...a[0]||(a[0]=[t('<h2 id="hadoop" tabindex="-1">Hadoop <a class="header-anchor" href="#hadoop" aria-label="Permalink to &quot;Hadoop&quot;">​</a></h2><p>Hadoop 是一个提供分布式存储和计算的开源软件框架，它具有无共享、高可用（HA）、弹性可扩展的特点，非常适合处理海量数量。Hadoop 提供了一套分布式系统基础架构，核心内容包含HDFS ( Hadoop Distributed File System, 分布式文件系统)、MapReduce计算引擎和YARN (Yet Another Resource Negotiator,另一种资源协调者)统一资源管理调度。</p><p><img src="https://mmbiz.qpic.cn/mmbiz_png/3Knwg6Nia2ncfAibkw9gVqIqAZs7gTIb4xGH7v64tgFv3A3M9zH92380JNmLmVPA3esmRs9SOLT8rviaejpOdYriaQ/640?wx_fmt=png&amp;wxfrom=5&amp;wx_lazy=1&amp;wx_co=1" alt="图片"></p><h3 id="hdfs" tabindex="-1">HDFS <a class="header-anchor" href="#hdfs" aria-label="Permalink to &quot;HDFS&quot;">​</a></h3><p>HDFS ( Hadoop Distributed File System）即 Hadoop 分布式文件系统，它的设计目标是把超<a href="http://c.biancheng.net/big_data/" target="_blank" rel="noreferrer">大数据</a>集存储到集群中的多台普通商用计算机上，并提供高可靠性和高吞吐量的服务。在 HDFS 中，文件最终是以数据块的形式存储的，而副本机制（副本个数可设置，默认为3）极大程度上避免了宕机所造成的数据丢失，可以在数据读取时进行数据校验。</p><p><img src="http://c.biancheng.net/uploads/allimg/191114/6-191114101011U7.gif" alt="img"></p><h4 id="namenode" tabindex="-1">NameNode <a class="header-anchor" href="#namenode" aria-label="Permalink to &quot;NameNode&quot;">​</a></h4><ul><li>管理 HDFS 的名称空间；</li><li>配置副本策略；</li><li>管理数据块(Block) 映射信息；</li><li>处理客户端读写请求。</li></ul><p>NameNode 是主服务器，负责管理文件系统的命名空间以及客户端对文件的访问。当客户端请求数据时，仅仅从 NameNode 中获取文件的元数据信息，具体的数据传输不经过 NameNode，而是直接与具体的 DataNode 进行交互。</p><p>这里文件的元数据信息记录了文件系统中的文件名和目录名，以及它们之间的层级关系，同时也记录了每个文件目录的所有者及其权限，甚至还记录每个文件由哪些块组成，这些元数据信息记录在文件 fsimage 中，当系统初次启动时，NameNode 将读取 fsimage 中的信息并保存到内存中。</p><p>这些块的位置信息是由 NameNode 启动后从每个 DataNode 获取并保存在内存当中的，这样既减少了 NameNode 的启动时间，又减少了读取数据的查询时间，提高了整个系统的效率。</p><h4 id="secondarynamenode" tabindex="-1">SecondaryNameNode <a class="header-anchor" href="#secondarynamenode" aria-label="Permalink to &quot;SecondaryNameNode&quot;">​</a></h4><p>NameNode 管理着元数据信息，元数据信息会定期保存到 镜像文件(fsimage)和编辑日志(editlog)文件中。其中的 edits 保存操作日志信息，在 HDFS 运行期间，新的操作日志不会立即与 fsimage 进行合并，也不会存到 NameNode 的内存中，而是会先写到 edits 中。当 edits 文件达到一定域值或间隔一段时间后触发 SecondaryNameNode 进行工作，这个时间点称为 checkpoint。</p><p>并非 NameNode 的热备。当 NameNode 挂掉的时候， 它并不能马上替换 NameNode 并提供服务。辅助 NameNode ，分 担其工 作量 ，比如定期合并Fsimage 和 Edits, 并推送给NameNode ；在紧急情况下，可辅助恢复 NameNode 。</p><h4 id="datanode" tabindex="-1">DataNode <a class="header-anchor" href="#datanode" aria-label="Permalink to &quot;DataNode&quot;">​</a></h4><p>DataNode 是 HDFS 中的工作节点，也是从服务器，它负责<strong>存储数据块</strong>，也负责为客户端提供数据块的<strong>读写服务</strong>，同时也响应 NameNode 的相关指令，如完成数据块的复制、删除等。</p><h3 id="mapreduce" tabindex="-1">MapReduce <a class="header-anchor" href="#mapreduce" aria-label="Permalink to &quot;MapReduce&quot;">​</a></h3><p>实现在集群服务器上分布式并行运算。MapReduce核心功能是将用户编写的业务逻辑代码和自带默认组件整合成一个完的分布式运算程序，并发运行在一个Hadoop集群上。缺点：</p><ul><li>不擅长实时计算MapReduce无法像MySQL一样，在毫秒或者秒级内返回结果</li><li>不擅长流式计算。流式计算的输入数据是动态的，而MapReduce的输入数据集是静态的，不能动态变化。</li></ul><p>MapReduce 编程模型只能包含一个 Map 阶段和一个 Reduce 阶段，如果用户的业务逻辑非常复杂，那就只能多个 MapReduce 程序，串行运行。</p><h3 id="yarn" tabindex="-1">YARN <a class="header-anchor" href="#yarn" aria-label="Permalink to &quot;YARN&quot;">​</a></h3><p>一种通用的资源管理系统和调度平台。帮用户调度大量的 MapReduce 程序，并合理分配运算资源（CPU和内存）。</p><p>资源管理系统 ：管理集群内的硬件资源，和程序运行相关，比如内存，CPU等。 调度平台：多个程序同时申请计算资源时提供分配，调度的规则（算法）。 通用：不仅仅支持MapReduce程序，理论上支持各种计算程序如spark，flink。yarn不关系程序的计算内容，只关心程序所需的资源，在程序申请资源的时候根据调度算法分配资源，计算结束之后回收计算资源。使用yarn作为资源调度平台的计算框架自身需要提供ApplicationMaster来负责计算任务的调度。</p><p>Yarn中有三种资源调度器：<a href="https://so.csdn.net/so/search?q=FIFO&amp;spm=1001.2101.3001.7020" target="_blank" rel="noreferrer">FIFO</a>调度器（FIFO Scheduler）、容量调度器（Capacity Scheduler）、公平调度器（Fair Scheduler）。</p><h2 id="参考" tabindex="-1">参考 <a class="header-anchor" href="#参考" aria-label="Permalink to &quot;参考&quot;">​</a></h2><ul><li><a href="https://blog.csdn.net/qq_40322236/article/details/128891963" target="_blank" rel="noreferrer"> Hadoop 简介 </a></li></ul>',26)])])}const N=e(r,[["render",i]]);export{h as __pageData,N as default};
